var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>작전 중 부상자 다수 발생! 다행히 사망자는 없습니다!</color>","JPN":"<color=#ffd34c>作戦中に負傷者多数発生！　幸い死亡者はいません！</color>","ENG":"<color=#ffd34c>We've got multiple casualties! But fortunately no K.I.A.s!</color>","TWN":"<color=#ffd34c>作戰中有多人受傷！幸好沒有人死亡！</color>"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>본부, 수배자에게는 전차포가 통하지 않습니다! 더 강한 화력이 필요합니다!</color>","JPN":"<color=#ffd34c>本部、指名手配犯には戦車砲が効きません！　より強い火力が必要です！</color>","ENG":"<color=#ffd34c>HQ, the anti-tank rounds have no effect on the suspect! Requesting more firepower!</color>","TWN":"<color=#ffd34c>總部，裝甲砲對通緝犯無效！需要更強的火力！</color>"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>도시를 쑥대밭으로 만들 생각이냐?! 허가할 수 없다!</color>","JPN":"<color=#ffd34c>都市をめちゃくちゃにするにするつもりか！？　許可できない！</color>","ENG":"<color=#ffd34c>Are you trying to raze the entire city?! Request denied!</color>","TWN":"<color=#ffd34c>你是想毀掉城市嗎？！我絕不允許！</color>"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>악천후 탓에 공중지원도 어렵습니다! 부탁드립니다!</color>","JPN":"<color=#ffd34c>悪天候のせいで空中からの支援も厳しいです！　お願いします！</color>","ENG":"<color=#ffd34c>We can't call in air support either due to inclement weather! Please, sir!</color>","TWN":"<color=#ffd34c>由於氣候不佳，也無法進行空中支援，Over！</color>"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"적대 개체 반응이 감지되지 않습니다.","JPN":"敵性個体反応が感知されません。","ENG":"Hostility no longer detected.","TWN":"未感應到敵對個體反應。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"잔여 동력은……. 현재 8.27퍼센트.","JPN":"残余エネルギーは……現在8.27％。","ENG":"Current remaining power is… 8.27%.","TWN":"剩餘動能…還有8.27%。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"빈번한 역장 생성이 동력 소비의 주요인이군요.","JPN":"頻繁なフォースシールドの生成がエネルギー消費の主要因ですね。","ENG":"The frequent generation of stasis fields appears to be most significant cause for the power drain.","TWN":"頻繁產生力場應該就是動能耗損的主因。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"CPU가 연산 부하를 견디지 못할 수 있습니다. 불필요한 교전은 되도록이면…….","JPN":"CPUが演算負荷に耐えられない可能性があります。不要な交戦はなるべく……","ENG":"The CPU may be unable to withstand the computational overload. I should avoid any unnecessary engagements…","TWN":"CPU無法承受運算負載壓力，盡可能避免不必要的衝突……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AIRPLANE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"추돌사고 발생. 시가전용 장갑차량.","JPN":"追突事故発生。市街戦用装甲車。","ENG":"Crash detected. Caused by Armored Vehicle for Urban Warfare.","TWN":"發生追撞事件，是巷戰裝甲戰車。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"태스크포스 <color=#ffd34c>블랙 타이드</color>의 식별신호 감지.","JPN":"タスクフォースカンパニー<color=#ffd34c>ブラックタイド</color>の識別信号を感知。","ENG":"TASKFORCE <color=#ffd34c>Black Tide</color> call sign detected.","TWN":"感應到是特遣勢力<color=#ffd34c>黑潮</color>的識別信號。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_06"},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……피할 계획이었습니다만. 이건 어렵겠군요.","JPN":"……避けるつもりでしたが。これは難しいですね。","ENG":"…So much for avoiding engagements. This one seems inevitable.","TWN":"……原本是想能免則免的，看來可能有困難。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"우와, 먼저 들이받았는데 채리엇이 찌그러졌네요.","JPN":"わあ、突っ込んだのはこっちなのに、チャリオットがぺちゃんこになりましたね。","ENG":"Wow, we're the ones who crashed into her, but the Chariot's all crumpled up.","TWN":"哇，我先撞上去後步戰車就凹咧？！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L21_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경찰차였으면 사망진단서 떼었어야겠는데요.","JPN":"パトカーだったら私たちの死亡診断書案件です。","ENG":"We'd be long gone if we tried this in our regular patrol car.","TWN":"如果是警車可能要開死亡證明。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GRENADE_TIDE_NULL_NULL","text":{"KOREA":"오우, 가슴 벌렁벌렁한 드라이브였어!","JPN":"おう、体がゾクゾクするドライブだったぜ！","ENG":"Dang, what a rush!","TWN":"哇喔～真是痛快的兜風！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L24_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"덕분에 눈 깜짝할 새 도착했군요! 협조 감사합니다!","JPN":"おかげさまであっという間に着きましたね！　ご協力ありがとうございます！","ENG":"But you got us here in a blink! Thanks for the help!","TWN":"多虧了你，一眨眼就到了呢！多謝你的協助！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L25_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"혼자 도시 경비대를 병원 신세 지게 만든 상대다! 전원 긴장을 늦추지 마라!","JPN":"単体で都市警備隊を戦闘不能にした相手だ！　全員気を抜くな！","ENG":"The suspect has put the entire City Guard out of commission by herself! Stay frosty, everyone!","TWN":"對方可是一個人就讓整個城市守衛隊都進醫院！大家提高警覺！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GRENADE_TIDE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L27_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"시민 안전을 위해 불철주야 고생이 많으십니다. 휴먼들.","JPN":"市民安全のためにいつもお疲れ様です、ヒューマン。","ENG":"I appreciate your tireless effort to ensure the safety of the citizens, humans.","TWN":"人類，你們日以繼夜地守護人民的安全，真是辛苦了。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"하지만 저는 가야 할 곳이 있습니다. 무의미한 적대행위는 삼가해 주십시오.","JPN":"しかし、私には行くべき場所があります。無意味な敵対行為は控えてください。","ENG":"But there is another matter I must attend to. Please refrain from meaningless hostilities.","TWN":"但我必須要去個地方，沒意義的衝突還請三思。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그럼 이것도 의미 없나 볼까?!","JPN":"それじゃあ、これも意味ないか確かめてみない！？","ENG":"Let's see if you find this meaningless!","TWN":"這個你也覺得沒意義嗎？！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_07"},{"id":"L31_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……의외로군요. 블랙 타이드의 카운터들 중에 당신처럼 어린 휴먼도 있었습니까.","JPN":"……意外ですね。ブラックタイドのカウンターには、あなたのような幼いヒューマンもいたのですか。","ENG":"…This is rather unexpected. I did not realize the Black Tide had such a young Counter among their ranks.","TWN":"……真是令人意外。黑潮的制裁者中，竟然有像你這麼年輕的人類嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L32_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"아니. 협조 요청을 받고 온 현직 경찰이다.","JPN":"いや、協力要請を受けてきた現役の警察よ。","ENG":"They don't. I'm a police officer responding to a interagency coordination request.","TWN":"不，我是收到請求來支援的現役警察。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"도주는 포기해. 의료 지원단 집단희생 사건의 용의자.","JPN":"逃走は諦めなさい。医療支援団の集団虐殺事件の容疑者。","ENG":"Don't even dream of getting away. You're suspected of massacring medical aid workers.","TWN":"別想逃，義診集體死亡事件的嫌犯！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"계속 저항해서 피해를 키운다면 공권력의 무서움을 가르쳐 주겠어.","JPN":"抵抗し続けて被害を拡大させるのなら、公権力の恐ろしさを思い知らせてやる。","ENG":"If you continue to resist and cause collateral damage, I'll show you the true might of law enforcement.","TWN":"若是再抵抗造成傷亡，我會讓你知道公權力的可怕！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저는 결백합니다. 따라서 공권력에 시달리는 건 넌센스 같군요, 휴먼.","JPN":"私は潔白です。したがって、公権力の恐ろしさを知るのはナンセンスです、ヒューマン。","ENG":"But I am innocent of any crime. Thus it seems out of turn that the law enforcement would target me, human.","TWN":"我是清白的，用公權力來威脅我有點荒謬，人類。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"이미 도시 한복판을 쑥대밭으로 만들어 놓고 그런 소릴 하는 거야?","JPN":"すでに都心のど真ん中をめちゃくちゃに破壊しておいて、よくそんなことが言えるわね？","ENG":"Innocent? You just demolished an entire city block.","TWN":"你把城市弄得一團亂，還有臉這麼說？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"네가 결백을 주장할 곳은 여기가 아니라 경찰서야!","JPN":"あなたの潔白を主張するべきところはここじゃなく警察署よ！","ENG":"Save your plea for the court!","TWN":"要主張你的清白也不是在這裡，跟我到警察局！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"긴 말 하지 않겠어! 순순히 서로 따라오시지!","JPN":"単刀直入に言うわ！　大人しく付いて来なさい！","ENG":"I'm only going to say this once. You have one chance to surrender!","TWN":"廢話少說，乖乖跟我去警察局！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};